class ToolUseAccuracyMeasurer:
    """Computes precision/recall/F1 for tool-call sequences.

    Handles parallel tool use: if the agent issues tool_a and tool_b
    in the same turn, both count as separate calls in the actual set.
    """

    def measure(
        self,
        actual_tool_calls: list[str],
        expected_tool_calls: list[str],
    ) -> dict[str, float]:
        """Return {precision, recall, f1} in [0.0, 1.0].

        Order-insensitive: measures coverage, not sequence fidelity.
        Use a separate sequence-alignment metric if order matters.
        """
        actual_set = set(actual_tool_calls)
        expected_set = set(expected_tool_calls)

        if not actual_set and not expected_set:
            # Both empty — agent correctly made no tool calls.
            return {"precision": 1.0, "recall": 1.0, "f1": 1.0}

        if not actual_set:
            return {"precision": 0.0, "recall": 0.0, "f1": 0.0}

        if not expected_set:
            # Agent called tools when none were expected.
            return {"precision": 0.0, "recall": 1.0, "f1": 0.0}
